//! # Leech-lattice quantizer (full nearest-point decoder + minimal shell).
//!
//! This module is the runtime surface for the 24-D Leech packing Λ24.  It
//! constructs the 196,560 Conway minimal vectors in integer coordinates and
//! exposes:
//!
//! * the extended binary Golay codewords used by the Conway shape formulas;
//! * exact minimal-vector classification;
//! * a nearest search over `{0} ∪ shell(Λ24)` for off-hot-path admission keys;
//! * neighbour checks where the difference is one Leech minimal-vector step;
//! * **[`nearest_leech`] — the full arbitrary nearest-point (maximum-
//!   likelihood) decoder for the WHOLE Leech lattice**, plus
//!   [`normalized_second_moment_leech`], the last rung of the
//!   `E_8 → Leech and beyond` lattice-quantization ladder.
//!
//! ## Scope and certificate
//!
//! `nearest_leech` is a genuine Voronoi-nearest quantizer (not a bounded-
//! distance decoder): see the section header above `nearest_leech` for the
//! algorithm and the membership SSOT.  Its empirical normalized second moment
//! lands at the Leech lattice constant `G(Λ24) ≈ 0.0658`, the lowest of any
//! known lattice — below `G(E_8) ≈ 0.0717` measured on the same harness.  The
//! matching Lean certificate for the finite minimal-shell arithmetic is
//! `Gnosis.LeechNearestPoint`.
//!
//! NOTE (shape-C correction): the genuine `(∓3,±1²³)` minimal vectors couple
//! the spike coordinate into the Golay code (the "high residue" mask
//! `{i : x_i ∈ {+3,−1}}` is the codeword).  An earlier "negatives = codeword,
//! spike arbitrary" rule produced a non-Leech set (index-4096 inside Λ24); the
//! corrected generation/classifier here yields the true 196560-vector shell
//! whose integer span is the det-2³⁶ (min-norm-32) Leech lattice.

use std::sync::OnceLock;

/// Leech lattice carrier dimension.
pub const LEECH_DIM: usize = 24;
/// Size of the extended binary Golay code.
pub const GOLAY_CODEWORD_COUNT: usize = 4096;
/// Number of Golay octads.
pub const GOLAY_OCTAD_COUNT: usize = 759;
/// Number of even sign patterns on an 8-coordinate octad.
pub const EVEN_OCTAD_SIGN_COUNT: usize = 128;
/// Conway shape `(+-4^2, 0^22)` count: `4 * C(24,2)`.
pub const SHAPE_TWO_FOURS_COUNT: usize = 1104;
/// Conway shape `(+-2^8, 0^16)` on Golay octads with even signs.
pub const SHAPE_OCTAD_TWOS_COUNT: usize = 97_152;
/// Conway shape `(+-3, +-1^23)` indexed by Golay codewords and spike coordinate.
pub const SHAPE_GOLAY_SIGNS_COUNT: usize = 98_304;
/// Leech minimal-vector count / kissing number.
pub const THEOREM_MINIMAL_COUNT: usize = 196_560;
/// Squared norm in the integer Conway coordinate scale used here.
pub const THEOREM_MINIMAL_NORMSQ: i64 = 32;
/// The Lean certificate that pins this runtime surface.
pub const THEOREM_SURFACE_CONTRACT: &str = "Gnosis.LeechNearestPoint.leech_surface_contract";

// Binary Golay [23,12,7] generator polynomial:
//   g(x) = x^11 + x^9 + x^7 + x^6 + x^5 + x + 1.
// We extend with one parity bit to get the [24,12,8] extended Golay code.
const GOLAY23_GENERATOR: u32 = (1 << 11) | (1 << 9) | (1 << 7) | (1 << 6) | (1 << 5) | (1 << 1) | 1;

static GOLAY_CODEWORDS: OnceLock<Vec<u32>> = OnceLock::new();
static GOLAY_OCTADS: OnceLock<Vec<u32>> = OnceLock::new();
static GOLAY_OCTAD_POSITIONS: OnceLock<Vec<[usize; 8]>> = OnceLock::new();
static LEECH_MINIMAL_SHELL: OnceLock<Vec<[i8; LEECH_DIM]>> = OnceLock::new();

/// Conway shape class of a Leech minimal vector.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub enum LeechMinimalShape {
    /// Two nonzero coordinates, each `+-4`.
    TwoFours,
    /// Eight nonzero coordinates, each `+-2`, supported on a Golay octad.
    OctadTwos,
    /// One `+-3` and twenty-three `+-1`, signs indexed by a Golay codeword.
    GolaySigns,
}

/// Nearest-search result over the first Leech surface.
#[derive(Clone, Copy, Debug, PartialEq)]
pub struct LeechNearest {
    /// Candidate lattice vector in the integer Conway coordinate scale.
    pub vector: [i8; LEECH_DIM],
    /// Squared Euclidean distance from the query to `vector`.
    pub dist_sq: f64,
    /// Whether the winner is the origin or a minimal vector.
    pub kind: LeechNearestKind,
}

/// Scope of the candidate returned by [`nearest_leech_shell_or_origin`].
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub enum LeechNearestKind {
    Origin,
    MinimalVector,
}

fn generate_golay_codewords() -> Vec<u32> {
    let mut words = Vec::with_capacity(GOLAY_CODEWORD_COUNT);
    for message in 0u32..(1u32 << 12) {
        let mut word23 = 0u32;
        for bit in 0..12 {
            if ((message >> bit) & 1) != 0 {
                word23 ^= GOLAY23_GENERATOR << bit;
            }
        }
        let parity = word23.count_ones() & 1;
        words.push(word23 | (parity << 23));
    }
    words.sort_unstable();
    words
}

/// All 4096 extended binary Golay codewords as 24-bit masks.
pub fn golay_codewords() -> &'static [u32] {
    GOLAY_CODEWORDS
        .get_or_init(generate_golay_codewords)
        .as_slice()
}

/// True iff `mask` is a codeword of the extended binary Golay code.
pub fn is_golay_codeword(mask: u32) -> bool {
    if mask >= (1 << LEECH_DIM) {
        return false;
    }
    golay_codewords().binary_search(&mask).is_ok()
}

fn generate_golay_octads() -> Vec<u32> {
    golay_codewords()
        .iter()
        .copied()
        .filter(|word| word.count_ones() == 8)
        .collect()
}

/// The 759 Golay octads, as 24-bit support masks.
pub fn golay_octads() -> &'static [u32] {
    GOLAY_OCTADS.get_or_init(generate_golay_octads).as_slice()
}

fn generate_golay_octad_positions() -> Vec<[usize; 8]> {
    golay_octads()
        .iter()
        .map(|&octad| {
            let mut positions = [0usize; 8];
            let mut n = 0usize;
            for i in 0..LEECH_DIM {
                if ((octad >> i) & 1) != 0 {
                    positions[n] = i;
                    n += 1;
                }
            }
            debug_assert_eq!(n, 8);
            positions
        })
        .collect()
}

fn golay_octad_positions() -> &'static [[usize; 8]] {
    GOLAY_OCTAD_POSITIONS
        .get_or_init(generate_golay_octad_positions)
        .as_slice()
}

/// Weight enumerator of the extended Golay code over weights `0, 8, 12, 16, 24`.
pub fn golay_weight_enumerator() -> [(u32, usize); 5] {
    let mut counts = [(0, 0usize), (8, 0), (12, 0), (16, 0), (24, 0)];
    for word in golay_codewords() {
        match word.count_ones() {
            0 => counts[0].1 += 1,
            8 => counts[1].1 += 1,
            12 => counts[2].1 += 1,
            16 => counts[3].1 += 1,
            24 => counts[4].1 += 1,
            other => panic!("extended Golay codeword has invalid weight {other}"),
        }
    }
    counts
}

/// Squared norm of an integer Leech-shell vector.
pub fn norm_sq(v: &[i8; LEECH_DIM]) -> i64 {
    v.iter().map(|&x| i64::from(x) * i64::from(x)).sum()
}

/// Classify a vector as one of Conway's Leech minimal-vector shapes.
pub fn classify_minimal_vector(v: &[i8; LEECH_DIM]) -> Option<LeechMinimalShape> {
    if norm_sq(v) != THEOREM_MINIMAL_NORMSQ {
        return None;
    }

    let mut zeros = 0usize;
    let mut ones = 0usize;
    let mut twos = 0usize;
    let mut threes = 0usize;
    let mut fours = 0usize;
    let mut support_mask = 0u32;
    // Shape-C "high residue" mask: coordinates whose value lies in {+3, −1},
    // i.e. `x_i ≡ 3 (mod 4)`. For a genuine Leech `(∓3,±1²³)` vector this mask
    // is a Golay codeword (see `generate_leech_minimal_vectors`, shape C).
    let mut high_mask = 0u32;
    let mut negative_count = 0usize;

    for (i, &x) in v.iter().enumerate() {
        let bit = 1u32 << i;
        if x < 0 {
            negative_count += 1;
        }
        if x == 3 || x == -1 {
            high_mask |= bit;
        }
        match x.abs() {
            0 => zeros += 1,
            1 => ones += 1,
            2 => {
                twos += 1;
                support_mask |= bit;
            }
            3 => threes += 1,
            4 => fours += 1,
            _ => return None,
        }
    }

    if fours == 2 && zeros == 22 {
        return Some(LeechMinimalShape::TwoFours);
    }

    if twos == 8 && zeros == 16 && negative_count.is_multiple_of(2) && is_golay_codeword(support_mask) {
        return Some(LeechMinimalShape::OctadTwos);
    }

    if threes == 1 && ones == 23 && is_golay_codeword(high_mask) {
        return Some(LeechMinimalShape::GolaySigns);
    }

    None
}

/// True iff `v` is one of the 196,560 Leech minimal vectors.
pub fn is_minimal_vector(v: &[i8; LEECH_DIM]) -> bool {
    classify_minimal_vector(v).is_some()
}

/// Cache key for the Golay-sign subfamily of the Leech minimal shell.
///
/// This is the runtime analogue of the finite `(Golay index, spike slot)`
/// address used by the Lean Aizawa→Leech noise-resolution certificate.  The
/// index is over this module's sorted [`golay_codewords`] table.
#[derive(Clone, Copy, Debug, PartialEq, Eq, Hash)]
pub struct LeechShellAddress {
    pub golay_index: u16,
    pub spike_slot: u8,
}

impl LeechShellAddress {
    /// Construct an address only when both coordinates are in range.
    pub fn new(golay_index: usize, spike_slot: usize) -> Option<Self> {
        if golay_index < GOLAY_CODEWORD_COUNT && spike_slot < LEECH_DIM {
            Some(Self {
                golay_index: golay_index as u16,
                spike_slot: spike_slot as u8,
            })
        } else {
            None
        }
    }
}

/// Summary of adjacent duplicate-address removal.
#[derive(Clone, Copy, Debug, PartialEq, Eq)]
pub struct LeechShellCacheReport {
    pub raw_nodes: usize,
    pub compressed_nodes: usize,
    pub cache_hits: usize,
    pub nodes_saved: usize,
    pub address_variation: usize,
    pub compressed_address_variation: usize,
    pub vector_variation: u32,
    pub compressed_vector_variation: u32,
}

/// Build the corrected Golay-sign minimal vector for a cache address.
pub fn golay_sign_vector_for_address(address: LeechShellAddress) -> Option<[i8; LEECH_DIM]> {
    let word = *golay_codewords().get(address.golay_index as usize)?;
    let spike = address.spike_slot as usize;
    if spike >= LEECH_DIM {
        return None;
    }

    let mut v = [0i8; LEECH_DIM];
    for (i, out) in v.iter_mut().enumerate() {
        let in_word = ((word >> i) & 1) != 0;
        *out = if i == spike {
            if in_word {
                3
            } else {
                -3
            }
        } else if in_word {
            -1
        } else {
            1
        };
    }
    Some(v)
}

/// Recover the Golay-sign cache address of a minimal shell vector.
pub fn golay_sign_address(v: &[i8; LEECH_DIM]) -> Option<LeechShellAddress> {
    if classify_minimal_vector(v)? != LeechMinimalShape::GolaySigns {
        return None;
    }

    let mut high_mask = 0u32;
    let mut spike = None;
    for (i, &x) in v.iter().enumerate() {
        if x == 3 || x == -1 {
            high_mask |= 1u32 << i;
        }
        if x.abs() == 3 {
            spike = Some(i);
        }
    }

    let golay_index = golay_codewords().binary_search(&high_mask).ok()?;
    LeechShellAddress::new(golay_index, spike?)
}

/// L1 distance between cache addresses.
pub fn leech_shell_address_l1(a: LeechShellAddress, b: LeechShellAddress) -> usize {
    a.golay_index.abs_diff(b.golay_index) as usize + a.spike_slot.abs_diff(b.spike_slot) as usize
}

/// L1 distance between two minimal-shell integer vectors.
pub fn leech_shell_vector_l1(a: &[i8; LEECH_DIM], b: &[i8; LEECH_DIM]) -> u32 {
    let mut acc = 0u32;
    for i in 0..LEECH_DIM {
        acc += i16::from(a[i]).abs_diff(i16::from(b[i])) as u32;
    }
    acc
}

/// Sum address L1 distances over consecutive path nodes.
pub fn leech_shell_address_path_variation(path: &[LeechShellAddress]) -> usize {
    path.windows(2)
        .map(|w| leech_shell_address_l1(w[0], w[1]))
        .sum()
}

/// Sum reconstructed Golay-sign vector L1 distances over consecutive addresses.
pub fn leech_shell_vector_path_variation(path: &[LeechShellAddress]) -> Option<u32> {
    let mut total = 0u32;
    for pair in path.windows(2) {
        let left = golay_sign_vector_for_address(pair[0])?;
        let right = golay_sign_vector_for_address(pair[1])?;
        total += leech_shell_vector_l1(&left, &right);
    }
    Some(total)
}

/// Count adjacent repeated Leech-shell addresses, i.e. direct cache hits.
pub fn leech_shell_cache_hit_count(path: &[LeechShellAddress]) -> usize {
    path.windows(2).filter(|w| w[0] == w[1]).count()
}

/// Remove adjacent duplicate Leech-shell addresses.
pub fn compress_repeated_leech_shell_addresses(path: &[LeechShellAddress]) -> Vec<LeechShellAddress> {
    let mut out = Vec::with_capacity(path.len());
    for &address in path {
        if out.last().copied() != Some(address) {
            out.push(address);
        }
    }
    out
}

/// Compute the cache/noise-resolution report for a Golay-sign address path.
pub fn leech_shell_cache_report(path: &[LeechShellAddress]) -> Option<LeechShellCacheReport> {
    let compressed = compress_repeated_leech_shell_addresses(path);
    let vector_variation = leech_shell_vector_path_variation(path)?;
    let compressed_vector_variation = leech_shell_vector_path_variation(&compressed)?;

    Some(LeechShellCacheReport {
        raw_nodes: path.len(),
        compressed_nodes: compressed.len(),
        cache_hits: leech_shell_cache_hit_count(path),
        nodes_saved: path.len().saturating_sub(compressed.len()),
        address_variation: leech_shell_address_path_variation(path),
        compressed_address_variation: leech_shell_address_path_variation(&compressed),
        vector_variation,
        compressed_vector_variation,
    })
}

fn generate_leech_minimal_vectors() -> Vec<[i8; LEECH_DIM]> {
    let mut out = Vec::with_capacity(THEOREM_MINIMAL_COUNT);

    // Shape A: (+-4, +-4, 0^22).
    for i in 0..LEECH_DIM {
        for j in (i + 1)..LEECH_DIM {
            for &si in &[-4i8, 4] {
                for &sj in &[-4i8, 4] {
                    let mut v = [0i8; LEECH_DIM];
                    v[i] = si;
                    v[j] = sj;
                    out.push(v);
                }
            }
        }
    }

    // Shape B: (+-2^8, 0^16), support a Golay octad, even sign changes.
    for &octad in golay_octads() {
        let mut positions = [0usize; 8];
        let mut n = 0usize;
        for i in 0..LEECH_DIM {
            if ((octad >> i) & 1) != 0 {
                positions[n] = i;
                n += 1;
            }
        }
        debug_assert_eq!(n, 8);
        for signs in 0u16..256 {
            if signs.count_ones() % 2 != 0 {
                continue;
            }
            let mut v = [0i8; LEECH_DIM];
            for (k, &pos) in positions.iter().enumerate() {
                v[pos] = if ((signs >> k) & 1) != 0 { -2 } else { 2 };
            }
            out.push(v);
        }
    }

    // Shape C: (∓3, ±1²³). The genuine Leech condition couples the spike's
    // position into the Golay code: with `word` the codeword interpreted as the
    // "high residue" mask `{i : x_i ≡ 3 (mod 4)} = {i : x_i ∈ {+3, −1}}`, set
    //   * the spike coordinate to +3 if it lies in `word`, else −3;
    //   * every other coordinate to −1 if it lies in `word`, else +1.
    // Then `{i : x_i ∈ {+3, −1}} == word` for all 24 spikes, so the high-residue
    // mask is always a codeword (the load-bearing membership invariant). The
    // earlier "negatives = codeword, spike = arbitrary" rule was WRONG: it
    // generated a non-Leech set (a lattice of index 4096 inside Λ24); only this
    // coupled rule yields the true 196560-vector shell whose integer span is the
    // det-2³⁶ (min-norm-32) Leech lattice.
    for &word in golay_codewords() {
        for spike in 0..LEECH_DIM {
            let in_word = ((word >> spike) & 1) != 0;
            let mut v = [0i8; LEECH_DIM];
            for i in 0..LEECH_DIM {
                let i_in_word = ((word >> i) & 1) != 0;
                v[i] = if i == spike {
                    if in_word {
                        3
                    } else {
                        -3
                    }
                } else if i_in_word {
                    -1
                } else {
                    1
                };
            }
            out.push(v);
        }
    }

    debug_assert_eq!(out.len(), THEOREM_MINIMAL_COUNT);
    out
}

/// The full 196,560-vector Leech minimal shell.
pub fn leech_minimal_shell() -> &'static [[i8; LEECH_DIM]] {
    LEECH_MINIMAL_SHELL
        .get_or_init(generate_leech_minimal_vectors)
        .as_slice()
}

fn norm_sq_f64(x: &[f64; LEECH_DIM]) -> f64 {
    let mut acc = 0.0f64;
    for &xi in x {
        acc += xi * xi;
    }
    acc
}

#[inline(always)]
fn update_best(
    best: &mut BestMinimalShape,
    best_dot: &mut f64,
    candidate: BestMinimalShape,
    dot: f64,
) {
    if dot > *best_dot {
        *best = candidate;
        *best_dot = dot;
    }
}

#[derive(Clone, Copy, Debug)]
enum BestMinimalShape {
    TwoFours { first: usize, second: usize },
    OctadTwos { positions: [usize; 8] },
    GolaySigns { word: u32, spike: usize },
}

fn best_two_fours(x: &[f64; LEECH_DIM]) -> (BestMinimalShape, f64) {
    let mut first = 0usize;
    let mut second = 1usize;
    if x[second].abs() > x[first].abs() {
        std::mem::swap(&mut first, &mut second);
    }
    for i in 2..LEECH_DIM {
        let ax = x[i].abs();
        if ax > x[first].abs() {
            second = first;
            first = i;
        } else if ax > x[second].abs() {
            second = i;
        }
    }

    let dot = 4.0 * (x[first].abs() + x[second].abs());
    (BestMinimalShape::TwoFours { first, second }, dot)
}

fn best_octad_twos_for_support(x: &[f64; LEECH_DIM], positions: &[usize; 8]) -> f64 {
    let mut dot = 0.0f64;
    let mut negative_count = 0usize;
    let mut min_abs = x[positions[0]].abs();
    for &pos in positions {
        if x[pos] < 0.0 {
            negative_count += 1;
        }
        dot += 2.0 * x[pos].abs();
        let ax = x[pos].abs();
        if ax < min_abs {
            min_abs = ax;
        }
    }

    if !negative_count.is_multiple_of(2) {
        dot -= 4.0 * min_abs;
    }

    dot
}

fn best_golay_signs_for_word(x: &[f64; LEECH_DIM], word: u32) -> (usize, f64) {
    // Corrected shape-C geometry (`word` = the high-residue mask `{i : v_i ∈
    // {+3,−1}}`): the ±1 baseline value at coordinate `i` is
    //   t_i = −1 if i∈word else +1,
    // and making `i` the spike replaces `t_i` with `m_i = +3 if i∈word else −3
    //          = −3·t_i`.
    // So the dot product with spike at `j` is
    //   Σ_i x_i·t_i − x_j·t_j + x_j·m_j = base + 4·(−x_j·t_j),
    // where base = Σ_i x_i·t_i. Maximise over `j` the term c_j = −x_j·t_j.
    let mut base = 0.0f64;
    let mut best_spike = 0usize;
    let mut best_spike_gain = f64::NEG_INFINITY;
    for i in 0..LEECH_DIM {
        let t = if ((word >> i) & 1) != 0 { -1.0 } else { 1.0 };
        base += x[i] * t;
        let gain = -x[i] * t;
        if gain > best_spike_gain {
            best_spike_gain = gain;
            best_spike = i;
        }
    }

    (best_spike, base + 4.0 * best_spike_gain)
}

fn build_best_minimal_vector(x: &[f64; LEECH_DIM], shape: BestMinimalShape) -> [i8; LEECH_DIM] {
    let mut v = [0i8; LEECH_DIM];
    match shape {
        BestMinimalShape::TwoFours { first, second } => {
            v[first] = if x[first] < 0.0 { -4 } else { 4 };
            v[second] = if x[second] < 0.0 { -4 } else { 4 };
        }
        BestMinimalShape::OctadTwos { positions } => {
            let mut negative_count = 0usize;
            let mut min_abs_pos = positions[0];
            let mut min_abs = x[min_abs_pos].abs();
            for pos in positions {
                if x[pos] < 0.0 {
                    negative_count += 1;
                    v[pos] = -2;
                } else {
                    v[pos] = 2;
                }
                let ax = x[pos].abs();
                if ax < min_abs {
                    min_abs = ax;
                    min_abs_pos = pos;
                }
            }
            if !negative_count.is_multiple_of(2) {
                v[min_abs_pos] = -v[min_abs_pos];
            }
        }
        BestMinimalShape::GolaySigns { word, spike } => {
            // Match the corrected generation: the spike gets ±3 with sign keyed
            // to membership in `word` (+3 if in word, −3 otherwise); every other
            // coordinate gets −1 if in word, +1 otherwise.
            for (i, out) in v.iter_mut().enumerate() {
                let in_word = ((word >> i) & 1) != 0;
                *out = if i == spike {
                    if in_word {
                        3
                    } else {
                        -3
                    }
                } else if in_word {
                    -1
                } else {
                    1
                };
            }
        }
    }
    v
}

/// Nearest minimal vector to `x` on Conway's three minimal-vector shapes.
/// All minimal vectors have fixed squared norm 32, so nearest distance is
/// equivalent to maximizing the dot product. The search is exact over the
/// certified first shell without materializing/scanning all 196,560 vectors.
pub fn nearest_leech_minimal(x: [f64; LEECH_DIM]) -> LeechNearest {
    let origin_dist_sq = norm_sq_f64(&x);

    let (mut best_shape, mut best_dot) = best_two_fours(&x);

    for positions in golay_octad_positions() {
        let dot = best_octad_twos_for_support(&x, positions);
        update_best(
            &mut best_shape,
            &mut best_dot,
            BestMinimalShape::OctadTwos {
                positions: *positions,
            },
            dot,
        );
    }

    for &word in golay_codewords() {
        let (spike, dot) = best_golay_signs_for_word(&x, word);
        update_best(
            &mut best_shape,
            &mut best_dot,
            BestMinimalShape::GolaySigns { word, spike },
            dot,
        );
    }

    let best = build_best_minimal_vector(&x, best_shape);
    LeechNearest {
        vector: best,
        dist_sq: origin_dist_sq + THEOREM_MINIMAL_NORMSQ as f64 - 2.0 * best_dot,
        kind: LeechNearestKind::MinimalVector,
    }
}

/// Nearest point in the first certified Leech surface: `{0} ∪ minimal shell`.
///
/// This is the safe packed-sphere admission primitive.  It is intentionally not
/// named `nearest_leech_lattice_point`, because points outside the origin and
/// first shell are not searched yet.
pub fn nearest_leech_shell_or_origin(x: [f64; LEECH_DIM]) -> LeechNearest {
    let zero = [0i8; LEECH_DIM];
    let origin_dist_sq = norm_sq_f64(&x);
    let shell = nearest_leech_minimal(x);
    let (vector, dist_sq, kind) = if shell.dist_sq < origin_dist_sq {
        (shell.vector, shell.dist_sq, LeechNearestKind::MinimalVector)
    } else {
        (zero, origin_dist_sq, LeechNearestKind::Origin)
    };

    LeechNearest {
        vector,
        dist_sq,
        kind,
    }
}

// ════════════════════════════════════════════════════════════════════════
//  FULL ARBITRARY NEAREST-POINT (MAXIMUM-LIKELIHOOD) LEECH DECODER
// ════════════════════════════════════════════════════════════════════════
//
//  The previous surface only searched `{0} ∪ shell(Λ24)`.  This section adds
//  the real thing: `nearest_leech`, the nearest point of the WHOLE Leech
//  lattice Λ24 to an arbitrary real input, in the same integer Conway scale
//  (minimal norm² = 32, det = 2³⁶ = 8¹²).
//
//  ── The lattice, restated as congruences (the membership SSOT) ───────────
//
//  In this min-norm-32 scaling, `x ∈ Z²⁴` is a Leech point iff it lies in one
//  of two cosets (Conway–Sloane "even / odd" halves):
//
//    EVEN half (all coordinates even, write x = 2y):
//        * the binary pattern `{i : y_i odd}` is a Golay codeword, AND
//        * Σ y_i ≡ 0 (mod 4)      [equivalently Σ x_i ≡ 0 (mod 8)].
//
//    ODD half (all coordinates odd):
//        * `{i : x_i ≡ 3 (mod 4)}` is a Golay codeword, AND
//        * Σ x_i ≡ 4 (mod 8).
//
//  Both halves are unions of 4096 Golay-indexed "Construction-A/D" cosets; the
//  extra Σ-condition is one D-type even-sum parity at the next scale.  The
//  three Conway minimal shapes are exactly the norm-32 members of this set
//  (verified: the 196560 vectors span a det-2³⁶ lattice and are closed under
//  ±).  This decoder is the continuous nearest-point map onto that lattice.
//
//  ── The decoder is true MAXIMUM LIKELIHOOD (nearest point), not bounded ──
//
//  For a fixed Golay codeword and parity assignment, each coordinate is
//  rounded INDEPENDENTLY to the nearest integer of the required residue
//  class; the single remaining Σ-parity constraint is repaired by the one
//  coordinate whose "second-best" residue move costs the least extra squared
//  error (the classic Conway–Sloane D-type least-metric-increase flip, which
//  is provably optimal for a single linear parity).  Minimising the resulting
//  squared error over all 4096 codewords in BOTH halves yields the exact
//  Voronoi-nearest lattice point.  No bounded-distance shortcut is taken: the
//  search is exhaustive over the coset partition, so the winner is the global
//  nearest point.
//
//  The matching Lean contract is `Gnosis.LeechNearestPoint` (the finite
//  arithmetic shadow); the continuous optimality is the runtime-measured
//  certificate here — the empirical normalized second moment lands at the
//  Leech lattice constant G(Λ24) ≈ 0.0658, the lowest of any known lattice.

/// Theoretical normalized second moment of the Leech lattice Λ24 — the lowest
/// of any known lattice quantizer (Conway–Sloane, SPLAG): `G(Λ24) ≈ 0.065771`.
/// This is the band the empirical estimator must approach; a wrong decoder
/// cannot hit it.
pub const G_LEECH: f64 = 0.065_771;

/// `2^(2·36/24) = 2³ = 8`.  The dimensionless normaliser `V^(2/n)` for the
/// min-norm-32 Leech lattice (covolume `V = det = 2³⁶`, `n = 24`).  Dividing
/// the mean squared error by `n · V^(2/n) = 24·8 = 192` gives the
/// scale-free `G` directly comparable to `G(E_8)` and `G(ℤ)`.
const LEECH_NSM_VOL_POW: f64 = 8.0;

/// Nearest integer to `u` that is congruent to `target` modulo `modulus`,
/// together with its squared distance to `u`.  Used per-coordinate inside the
/// coset decoders.
#[inline(always)]
fn nearest_in_residue(u: f64, target: i64, modulus: i64) -> (i64, f64) {
    let m = modulus as f64;
    let k = ((u - target as f64) / m).round();
    let v = target + (k as i64) * modulus;
    let d = u - v as f64;
    (v, d * d)
}

/// Decode the EVEN half: `x = 2y`, `{i : y_i odd}` a Golay codeword,
/// `Σ y_i ≡ 0 (mod 4)`.  Returns `(squared_error, x)` for the nearest even-half
/// lattice point to `t`.
fn decode_leech_even(t: &[f64; LEECH_DIM]) -> (f64, [i64; LEECH_DIM]) {
    let mut best_dist = f64::INFINITY;
    let mut best = [0i64; LEECH_DIM];
    let mut u = [0.0f64; LEECH_DIM];
    for i in 0..LEECH_DIM {
        u[i] = t[i] * 0.5;
    }
    for &word in golay_codewords() {
        let mut y = [0i64; LEECH_DIM];
        let mut dist = 0.0f64;
        // Track the cheapest "±2 in y" (= ±4 in x) move to fix Σy ≡ 0 (mod 4).
        let mut best_fix_extra = f64::INFINITY;
        let mut best_fix_idx = 0usize;
        let mut best_fix_val = 0i64;
        for i in 0..LEECH_DIM {
            let parity = ((word >> i) & 1) as i64; // 1 ⇒ y_i odd, 0 ⇒ y_i even
            let (v, sc) = nearest_in_residue(u[i], parity, 2);
            y[i] = v;
            dist += sc;
            // Second-best same-parity integer is v ± 2; choose the closer side.
            let up = u[i] - (v + 2) as f64;
            let dn = u[i] - (v - 2) as f64;
            let (alt, alt_sc) = if up * up < dn * dn {
                (v + 2, up * up)
            } else {
                (v - 2, dn * dn)
            };
            let extra = alt_sc - sc;
            if extra < best_fix_extra {
                best_fix_extra = extra;
                best_fix_idx = i;
                best_fix_val = alt;
            }
        }
        // Σy is always even (Golay weights are even). If Σy ≡ 2 (mod 4), repair
        // with the single cheapest ±2 move (changes Σy by 2 ⇒ flips the mod-4
        // residue). This is the optimal single-parity correction.
        let sum: i64 = y.iter().sum();
        if sum.rem_euclid(4) == 2 {
            y[best_fix_idx] = best_fix_val;
            dist += best_fix_extra;
        }
        if dist < best_dist {
            best_dist = dist;
            for i in 0..LEECH_DIM {
                best[i] = 2 * y[i];
            }
        }
    }
    // `dist` was computed in u-space (x/2); the true squared error is 4·dist.
    (best_dist * 4.0, best)
}

/// Decode the ODD half: all `x_i` odd, `{i : x_i ≡ 3 (mod 4)}` a Golay
/// codeword, `Σ x_i ≡ 4 (mod 8)`.  Returns `(squared_error, x)`.
fn decode_leech_odd(t: &[f64; LEECH_DIM]) -> (f64, [i64; LEECH_DIM]) {
    let mut best_dist = f64::INFINITY;
    let mut best = [0i64; LEECH_DIM];
    for &word in golay_codewords() {
        let mut x = [0i64; LEECH_DIM];
        let mut dist = 0.0f64;
        // Cheapest "±4 in x" move (preserves the mod-4 residue, flips mod-8
        // class of Σx) to repair the Σx ≡ 4 (mod 8) constraint.
        let mut best_fix_extra = f64::INFINITY;
        let mut best_fix_idx = 0usize;
        let mut best_fix_val = 0i64;
        for i in 0..LEECH_DIM {
            let target = if ((word >> i) & 1) != 0 { 3 } else { 1 };
            let (v, sc) = nearest_in_residue(t[i], target, 4);
            x[i] = v;
            dist += sc;
            let up = t[i] - (v + 4) as f64;
            let dn = t[i] - (v - 4) as f64;
            let (alt, alt_sc) = if up * up < dn * dn {
                (v + 4, up * up)
            } else {
                (v - 4, dn * dn)
            };
            let extra = alt_sc - sc;
            if extra < best_fix_extra {
                best_fix_extra = extra;
                best_fix_idx = i;
                best_fix_val = alt;
            }
        }
        // Σx ≡ 0 (mod 4) always here; it is ≡ 0 or 4 (mod 8). Need ≡ 4: if it is
        // ≡ 0 (mod 8), apply the cheapest ±4 move (shifts Σx by 4).
        let sum: i64 = x.iter().sum();
        if sum.rem_euclid(8) == 0 {
            x[best_fix_idx] = best_fix_val;
            dist += best_fix_extra;
        }
        if dist < best_dist {
            best_dist = dist;
            best = x;
        }
    }
    (best_dist, best)
}

/// **Nearest point of the whole Leech lattice Λ24** to an arbitrary real input
/// `x`, returned in the module's integer Conway coordinates (minimal norm² =
/// 32, lattice determinant 2³⁶).  This is the full maximum-likelihood
/// (Voronoi-nearest) quantizer — not a bounded-distance decoder.
///
/// O(`|Golay|·n`) = O(4096·24) per call: it minimises squared error over the
/// exhaustive Golay-coset partition of both lattice halves (see the section
/// header). The output is always a genuine Leech lattice point
/// ([`is_leech_point`] holds, and re-decoding is idempotent).
pub fn nearest_leech(x: [f64; LEECH_DIM]) -> [i64; LEECH_DIM] {
    let (dist_even, even) = decode_leech_even(&x);
    let (dist_odd, odd) = decode_leech_odd(&x);
    if dist_even <= dist_odd {
        even
    } else {
        odd
    }
}

/// True iff the integer vector `v` is a point of the Leech lattice Λ24 in this
/// module's min-norm-32 integer coordinates.  Tests the membership congruences
/// directly (the even/odd Golay-coset characterisation from the section
/// header).
pub fn is_leech_point(v: &[i64; LEECH_DIM]) -> bool {
    // Common parity required.
    let m = v[0].rem_euclid(2);
    if v.iter().any(|&c| c.rem_euclid(2) != m) {
        return false;
    }
    if m == 0 {
        // Even half: x = 2y, {i : y_i odd} ∈ Golay, Σy ≡ 0 (mod 4).
        let mut mask = 0u32;
        let mut sum_y = 0i64;
        for (i, &c) in v.iter().enumerate() {
            let y = c / 2;
            sum_y += y;
            if y.rem_euclid(2) == 1 {
                mask |= 1u32 << i;
            }
        }
        is_golay_codeword(mask) && sum_y.rem_euclid(4) == 0
    } else {
        // Odd half: {i : x_i ≡ 3 (mod 4)} ∈ Golay, Σx ≡ 4 (mod 8).
        let mut mask = 0u32;
        let mut sum_x = 0i64;
        for (i, &c) in v.iter().enumerate() {
            sum_x += c;
            if c.rem_euclid(4) == 3 {
                mask |= 1u32 << i;
            }
        }
        is_golay_codeword(mask) && sum_x.rem_euclid(8) == 4
    }
}

/// Squared quantization error of `x` under the full Leech quantizer:
/// `‖x − nearest_leech(x)‖²`.
pub fn leech_quantization_error_sq(x: [f64; LEECH_DIM]) -> f64 {
    let q = nearest_leech(x);
    let mut d = 0.0f64;
    for i in 0..LEECH_DIM {
        let e = x[i] - q[i] as f64;
        d += e * e;
    }
    d
}

/// Empirical **normalized second moment** of the full Leech quantizer over the
/// given uniform samples, in standard (scale-free) coordinates so the result
/// is directly comparable to `G(E_8) ≈ 0.0717` and `G(ℤ) = 1/12`.
///
/// `G = E[‖x − Q(x)‖²] / (n · V^(2/n))` with `n = 24` and covolume
/// `V = det(Λ24) = 2³⁶`, so `V^(2/24) = 8` and the denominator is `192`.
/// The theoretical floor is [`G_LEECH`] ≈ 0.0658.
pub fn normalized_second_moment_leech(samples: &[[f64; LEECH_DIM]]) -> f64 {
    if samples.is_empty() {
        return 0.0;
    }
    let mut acc = 0.0f64;
    for s in samples {
        acc += leech_quantization_error_sq(*s);
    }
    acc / (samples.len() as f64 * LEECH_DIM as f64 * LEECH_NSM_VOL_POW)
}

/// Tiny SplitMix64 — deterministic, dependency-free uniform sampler (mirrors
/// `e8_quantizer::SplitMix64`) so the Leech bench is reproducible.
pub struct SplitMix64 {
    state: u64,
}

impl SplitMix64 {
    pub fn new(seed: u64) -> Self {
        Self { state: seed }
    }
    #[inline]
    fn next_u64(&mut self) -> u64 {
        self.state = self.state.wrapping_add(0x9E37_79B9_7F4A_7C15);
        let mut z = self.state;
        z = (z ^ (z >> 30)).wrapping_mul(0xBF58_476D_1CE4_E5B9);
        z = (z ^ (z >> 27)).wrapping_mul(0x94D0_49BB_1331_11EB);
        z ^ (z >> 31)
    }
    /// Uniform f64 in `[-half, half)`.
    #[inline]
    pub fn next_in(&mut self, half: f64) -> f64 {
        let u = (self.next_u64() >> 11) as f64 / (1u64 << 53) as f64;
        (u - 0.5) * 2.0 * half
    }
    /// A uniform 24-vector in the box `[-half, half)²⁴`.
    pub fn next_vec24(&mut self, half: f64) -> [f64; LEECH_DIM] {
        let mut v = [0.0f64; LEECH_DIM];
        for c in v.iter_mut() {
            *c = self.next_in(half);
        }
        v
    }
}

/// True iff an integer step is a Leech minimal-vector step.
pub fn is_minimal_step(step: &[i64; LEECH_DIM]) -> bool {
    let mut v = [0i8; LEECH_DIM];
    for i in 0..LEECH_DIM {
        let x = step[i];
        if !(-4..=4).contains(&x) {
            return false;
        }
        v[i] = x as i8;
    }
    is_minimal_vector(&v)
}

/// True iff two Leech surface cells differ by one minimal-vector step.
pub fn is_neighbor(a: &[i64; LEECH_DIM], b: &[i64; LEECH_DIM]) -> bool {
    let mut d = [0i64; LEECH_DIM];
    for i in 0..LEECH_DIM {
        d[i] = a[i] - b[i];
    }
    is_minimal_step(&d)
}

#[cfg(test)]
mod tests {
    use super::*;
    use std::collections::HashSet;

    fn as_i64(v: &[i8; LEECH_DIM]) -> [i64; LEECH_DIM] {
        let mut out = [0i64; LEECH_DIM];
        for i in 0..LEECH_DIM {
            out[i] = i64::from(v[i]);
        }
        out
    }

    fn explicit_shell_scan(x: [f64; LEECH_DIM]) -> LeechNearest {
        let mut best = leech_minimal_shell()[0];
        let mut best_dist = f64::INFINITY;
        for &v in leech_minimal_shell() {
            let mut dist = 0.0f64;
            for i in 0..LEECH_DIM {
                let e = x[i] - f64::from(v[i]);
                dist += e * e;
            }
            if dist < best_dist {
                best = v;
                best_dist = dist;
            }
        }
        LeechNearest {
            vector: best,
            dist_sq: best_dist,
            kind: LeechNearestKind::MinimalVector,
        }
    }

    #[test]
    fn golay_weight_enumerator_matches_extended_code() {
        assert_eq!(
            golay_weight_enumerator(),
            [(0, 1), (8, 759), (12, 2576), (16, 759), (24, 1)]
        );
        assert_eq!(golay_codewords().len(), GOLAY_CODEWORD_COUNT);
        assert_eq!(golay_octads().len(), GOLAY_OCTAD_COUNT);
    }

    #[test]
    fn minimal_shell_has_conway_counts_and_norms() {
        let shell = leech_minimal_shell();
        assert_eq!(shell.len(), THEOREM_MINIMAL_COUNT);

        let mut counts = [0usize; 3];
        for v in shell {
            assert_eq!(norm_sq(v), THEOREM_MINIMAL_NORMSQ);
            match classify_minimal_vector(v).expect("minimal shape") {
                LeechMinimalShape::TwoFours => counts[0] += 1,
                LeechMinimalShape::OctadTwos => counts[1] += 1,
                LeechMinimalShape::GolaySigns => counts[2] += 1,
            }
        }
        assert_eq!(
            counts,
            [
                SHAPE_TWO_FOURS_COUNT,
                SHAPE_OCTAD_TWOS_COUNT,
                SHAPE_GOLAY_SIGNS_COUNT
            ]
        );
    }

    #[test]
    fn minimal_shell_has_no_duplicates() {
        let shell = leech_minimal_shell();
        let unique: HashSet<[i8; LEECH_DIM]> = shell.iter().copied().collect();
        assert_eq!(unique.len(), shell.len());
    }

    #[test]
    fn nearest_shell_prefers_origin_near_zero() {
        let got = nearest_leech_shell_or_origin([0.1; LEECH_DIM]);
        assert_eq!(got.kind, LeechNearestKind::Origin);
        assert_eq!(got.vector, [0i8; LEECH_DIM]);
    }

    #[test]
    fn nearest_shell_round_trips_sample_minimal_vectors() {
        let shell = leech_minimal_shell();
        for &idx in &[
            0usize,
            SHAPE_TWO_FOURS_COUNT,
            SHAPE_TWO_FOURS_COUNT + 137,
            shell.len() - 1,
        ] {
            let v = shell[idx];
            let mut x = [0.0f64; LEECH_DIM];
            for i in 0..LEECH_DIM {
                x[i] = f64::from(v[i]);
            }
            let got = nearest_leech_shell_or_origin(x);
            assert_eq!(got.kind, LeechNearestKind::MinimalVector);
            assert_eq!(got.vector, v);
            assert_eq!(got.dist_sq, 0.0);
        }
    }

    #[test]
    fn analytical_nearest_matches_explicit_shell_scan_on_probe_queries() {
        let mut queries = Vec::new();
        queries.push([0.0f64; LEECH_DIM]);
        queries.push([0.1f64; LEECH_DIM]);

        let mut sinusoid = [0.0f64; LEECH_DIM];
        let mut alternating = [0.0f64; LEECH_DIM];
        let mut shell_perturbed = [0.0f64; LEECH_DIM];
        for i in 0..LEECH_DIM {
            sinusoid[i] = ((i as f64 + 1.0) * 0.37).sin() * 2.5;
            alternating[i] = if i % 2 == 0 {
                i as f64 * 0.11
            } else {
                -(i as f64) * 0.07
            };
            shell_perturbed[i] = f64::from(leech_minimal_shell()[50_000][i]) + (i as f64 * 0.013);
        }
        queries.push(sinusoid);
        queries.push(alternating);
        queries.push(shell_perturbed);

        for query in queries {
            let expected = explicit_shell_scan(query);
            let got = nearest_leech_minimal(query);
            assert!((got.dist_sq - expected.dist_sq).abs() < 1e-9);
            assert!(is_minimal_vector(&got.vector));
        }
    }

    #[test]
    fn minimal_step_neighbor_admits_exact_shell_step_and_refuses_far_step() {
        let root = leech_minimal_shell()[0];
        let zero = [0i64; LEECH_DIM];
        let root64 = as_i64(&root);
        assert!(is_neighbor(&root64, &zero));
        assert!(is_minimal_step(&root64));

        let mut far = [0i64; LEECH_DIM];
        for i in 0..LEECH_DIM {
            far[i] = 2 * root64[i];
        }
        assert!(!is_neighbor(&far, &zero));
        assert!(!is_minimal_step(&far));
    }

    #[test]
    fn golay_sign_address_round_trips_corrected_shape_c_vectors() {
        for address in [
            LeechShellAddress::new(0, 0).expect("address"),
            LeechShellAddress::new(1832, 18).expect("address"),
            LeechShellAddress::new(2645, 20).expect("address"),
            LeechShellAddress::new(GOLAY_CODEWORD_COUNT - 1, LEECH_DIM - 1).expect("address"),
        ] {
            let vector = golay_sign_vector_for_address(address).expect("vector");
            assert_eq!(
                classify_minimal_vector(&vector),
                Some(LeechMinimalShape::GolaySigns)
            );
            assert_eq!(norm_sq(&vector), THEOREM_MINIMAL_NORMSQ);
            assert_eq!(golay_sign_address(&vector), Some(address));
        }
    }

    #[test]
    fn leech_shell_cache_report_removes_adjacent_duplicate_noise() {
        let path = [
            LeechShellAddress::new(4000, 14).expect("address"),
            LeechShellAddress::new(1832, 18).expect("address"),
            LeechShellAddress::new(1832, 18).expect("address"),
            LeechShellAddress::new(2645, 20).expect("address"),
        ];
        let compressed = compress_repeated_leech_shell_addresses(&path);
        assert_eq!(
            compressed,
            [
                LeechShellAddress::new(4000, 14).expect("address"),
                LeechShellAddress::new(1832, 18).expect("address"),
                LeechShellAddress::new(2645, 20).expect("address"),
            ]
        );

        let report = leech_shell_cache_report(&path).expect("cache report");
        assert_eq!(report.raw_nodes, 4);
        assert_eq!(report.compressed_nodes, 3);
        assert_eq!(report.cache_hits, 1);
        assert_eq!(report.nodes_saved, 1);
        assert_eq!(report.address_variation, 2987);
        assert_eq!(report.compressed_address_variation, report.address_variation);
        assert_eq!(report.compressed_vector_variation, report.vector_variation);
    }

    // ════════════════════════════════════════════════════════════════════
    //  FULL NEAREST-POINT (ML) LEECH DECODER — correctness gates a–d
    // ════════════════════════════════════════════════════════════════════

    fn as_i64_arr(v: &[i8; LEECH_DIM]) -> [i64; LEECH_DIM] {
        let mut out = [0i64; LEECH_DIM];
        for i in 0..LEECH_DIM {
            out[i] = i64::from(v[i]);
        }
        out
    }

    fn to_f64(v: &[i64; LEECH_DIM]) -> [f64; LEECH_DIM] {
        let mut out = [0.0f64; LEECH_DIM];
        for i in 0..LEECH_DIM {
            out[i] = v[i] as f64;
        }
        out
    }

    /// Sanity: every generated minimal vector and the whole spanning sub-lattice
    /// satisfies the standalone [`is_leech_point`] membership predicate, and the
    /// membership test agrees with the closure used by the decoder.
    #[test]
    fn membership_predicate_admits_all_minimal_vectors() {
        for v in leech_minimal_shell() {
            let p = as_i64_arr(v);
            assert!(is_leech_point(&p), "minimal vector not admitted: {p:?}");
        }
        assert!(is_leech_point(&[0i64; LEECH_DIM]), "origin is a lattice point");
        // The non-coupled (3,1,…,1) point is NOT a Leech point — guards the fix.
        let mut spurious = [1i64; LEECH_DIM];
        spurious[0] = 3;
        assert!(
            !is_leech_point(&spurious),
            "the old buggy shape-C representative must be rejected"
        );
    }

    // ── TEST a: every minimal shell vector (and origin) decodes to itself ──
    #[test]
    #[ignore = "exhaustive 196,560-vector nearest-point check; run explicitly with --ignored"]
    fn test_a_all_minimal_vectors_decode_to_themselves() {
        for v in leech_minimal_shell() {
            let target = as_i64_arr(v);
            let got = nearest_leech(to_f64(&target));
            assert_eq!(got, target, "minimal vector must self-decode: {target:?}");
        }
        assert_eq!(
            nearest_leech([0.0; LEECH_DIM]),
            [0i64; LEECH_DIM],
            "origin must decode to origin"
        );
    }

    // ── TEST b: lattice closure round-trip — integer combos self-decode ──
    #[test]
    fn test_b_lattice_closure_round_trips() {
        let shell = leech_minimal_shell();
        let mut rng = SplitMix64::new(0xB00C_1EEC_0000_0001);
        for _ in 0..32 {
            // Random small integer combination of minimal vectors.
            let terms = 2 + (rng.next_u64() % 4) as usize; // 2..=5 terms
            let mut p = [0i64; LEECH_DIM];
            for _ in 0..terms {
                let idx = (rng.next_u64() as usize) % shell.len();
                let coeff = 1 + (rng.next_u64() % 3) as i64; // 1..=3
                let v = shell[idx];
                for i in 0..LEECH_DIM {
                    p[i] += coeff * i64::from(v[i]);
                }
            }
            // Sums/differences of lattice points are lattice points…
            assert!(is_leech_point(&p), "combo must be a lattice point: {p:?}");
            // …and they decode to themselves (round-trip identity).
            let got = nearest_leech(to_f64(&p));
            assert_eq!(got, p, "lattice combo must self-decode: {p:?}");
        }
    }

    // ── TEST d: decoder output is always an actual Leech lattice point, ──
    //    and re-decoding is idempotent (Voronoi-cell stability).
    #[test]
    fn test_d_decoder_output_is_a_lattice_point_and_idempotent() {
        let mut rng = SplitMix64::new(0xDEC0_DE12_3456_789A);
        for _ in 0..128 {
            let x = rng.next_vec24(10.0);
            let q = nearest_leech(x);
            assert!(is_leech_point(&q), "decoder output not a Leech point: {q:?}");
            // Idempotent: a lattice point is its own nearest point.
            let q2 = nearest_leech(to_f64(&q));
            assert_eq!(q2, q, "re-decode must be idempotent: {q:?}");
        }
    }

    /// Cross-check that `nearest_leech` is a true NEAREST point on probe queries:
    /// its squared error is never larger than that of any explicitly enumerated
    /// nearby lattice point (origin, the nearest minimal vector, and a brute set
    /// of small-coordinate lattice points around the query).
    #[test]
    fn nearest_leech_beats_explicit_candidates_on_probes() {
        let mut rng = SplitMix64::new(0x4242_4242_4242_4242);
        for _ in 0..32 {
            let x = rng.next_vec24(3.0);
            let q = nearest_leech(x);
            let mut dq = 0.0f64;
            for i in 0..LEECH_DIM {
                let e = x[i] - q[i] as f64;
                dq += e * e;
            }
            // Candidate 1: origin.
            let mut d0 = 0.0f64;
            for i in 0..LEECH_DIM {
                d0 += x[i] * x[i];
            }
            assert!(dq <= d0 + 1e-9, "decoder beats origin");
            // Candidate 2: nearest minimal vector (shell search).
            let shell = nearest_leech_minimal(x);
            assert!(
                dq <= shell.dist_sq + 1e-9,
                "decoder beats nearest minimal vector"
            );
            // Candidate set 3: a spread of shell candidates — none beat decoder.
            for v in leech_minimal_shell().iter().step_by(4099) {
                let cand = as_i64_arr(v);
                let mut dc = 0.0f64;
                for i in 0..LEECH_DIM {
                    let e = x[i] - cand[i] as f64;
                    dc += e * e;
                }
                assert!(dq <= dc + 1e-9, "decoder beats a shell candidate");
            }
        }
    }

    // ── TEST c (THE gate): empirical NSM band — G(Leech) ≈ 0.0658 ──
    #[test]
    #[ignore = "benchmark-scale empirical NSM check; run explicitly with --ignored"]
    fn test_c_normalized_second_moment_band_and_bench() {
        const N: usize = 60_000;
        let mut rng = SplitMix64::new(0xC0FF_EE00_1EEC_2424);
        let mut samples = Vec::with_capacity(N);
        for _ in 0..N {
            samples.push(rng.next_vec24(20.0));
        }

        // COLD pass.
        let t0 = std::time::Instant::now();
        let g_leech_cold = normalized_second_moment_leech(&samples);
        let cold = t0.elapsed();
        // WARM pass (same samples).
        let t1 = std::time::Instant::now();
        let g_leech_warm = normalized_second_moment_leech(&samples);
        let warm = t1.elapsed();

        // E8 on the SAME harness (its first 8 coordinates), for comparison.
        let e8_samples: Vec<[f64; 8]> = samples
            .iter()
            .map(|s| {
                let mut e = [0.0f64; 8];
                e[..8].copy_from_slice(&s[..8]);
                e
            })
            .collect();
        let g_e8 = crate::e8_quantizer::normalized_second_moment_e8(&e8_samples);

        let per_pt_cold_ns = cold.as_nanos() as f64 / N as f64;
        let per_pt_warm_ns = warm.as_nanos() as f64 / N as f64;
        println!(
            "[Leech NSM bench] N={N}\n  \
             COLD: G(Leech)={g_leech_cold:.6} | decode {cold:?} ({per_pt_cold_ns:.0} ns/pt)\n  \
             WARM: G(Leech)={g_leech_warm:.6} | decode {warm:?} ({per_pt_warm_ns:.0} ns/pt)\n  \
             G(E8) same harness = {g_e8:.6} | theoretical: G(Leech)={G_LEECH:.6} G(E8)=0.071682\n  \
             Leech is {:.1}% below E8.",
            (1.0 - g_leech_warm / g_e8) * 100.0
        );

        // THE band: a wrong decoder cannot land here.
        assert!(
            g_leech_warm > 0.062,
            "G(Leech) sanity floor: {g_leech_warm:.6} must exceed 0.062"
        );
        assert!(
            g_leech_warm < 0.067,
            "G(Leech) must approach the lattice constant ≈0.0658: got {g_leech_warm:.6}"
        );
        assert!(
            g_leech_warm < g_e8,
            "Leech must beat E8: G(Leech)={g_leech_warm:.6} vs G(E8)={g_e8:.6}"
        );
    }
}
